import React from 'react';
import ReactDOM from 'react-dom';
import * as $ from 'jquery'
import './index.css';
import App from './App';
import profileContext from './components/context/profilecontext'
import CartContext from './components/context/profilecontext'

ReactDOM.render(
  <React.StrictMode>
    <CartContext>
    <profileContext>
      <App />
    </profileContext>
    </CartContext>
  </React.StrictMode>,
  document.getElementById('root')
);
